import React from "react";

function ViewSubmissionModal({

    open,

    submission,

    onClose

}) {

    if (!open || !submission) {

        return null;

    }

    return (

        <div
            style={{

                position: "fixed",

                top: 0,

                left: 0,

                width: "100%",

                height: "100%",

                background:
                    "rgba(0,0,0,.5)",

                display: "flex",

                justifyContent:
                    "center",

                alignItems:
                    "center",

                zIndex: 9999

            }}
        >

            <div
                style={{

                    width: "85%",

                    maxHeight: "90vh",

                    overflowY: "auto",

                    background: "#fff",

                    borderRadius: "15px",

                    padding: "25px"

                }}
            >

                <div
                    style={{

                        display: "flex",

                        justifyContent:
                            "space-between",

                        alignItems:
                            "center",

                        marginBottom: "25px"

                    }}
                >

                    <h2>

                        Faculty Submission

                    </h2>

                    <button

                        onClick={onClose}

                        style={{

                            border: "none",

                            background:
                                "#dc2626",

                            color: "#fff",

                            padding:
                                "8px 15px",

                            borderRadius:
                                "8px",

                            cursor:
                                "pointer"

                        }}

                    >

                        Close

                    </button>

                </div>

                <hr />

                <h3>

                    Faculty Details

                </h3>

                <p>

                    <strong>Name :</strong>

                    {" "}

                    {

                        submission.submittedByName

                    }

                </p>

                <p>

                    <strong>Email :</strong>

                    {" "}

                    {

                        submission.submittedByEmail

                    }

                </p>

                <p>

                    <strong>Department :</strong>

                    {" "}

                    {

                        submission.department

                    }

                </p>

                <p>

                    <strong>Quarter :</strong>

                    {" "}

                    {

                        submission.quarter

                    }

                </p>

                <p>

                    <strong>Status :</strong>

                    {" "}

                    {

                        submission.status

                    }

                </p>

                <hr />

                <h3>

                    Questions & Answers

                </h3>

                {

                    submission.answers?.length > 0 ?

                        submission.answers.map(

                            (item) => (

                                <div

                                    key={

                                        item.questionNo

                                    }

                                    style={{

                                        marginBottom:
                                            "20px",

                                        padding:
                                            "15px",

                                        border:
                                            "1px solid #e5e7eb",

                                        borderRadius:
                                            "10px"

                                    }}

                                >

                                    <strong>

                                        Q{

                                            item.questionNo

                                        }

                                        .

                                        {" "}

                                        {

                                            item.question

                                        }

                                    </strong>

                                    <p
                                        style={{
                                            marginTop:
                                                "10px"
                                        }}
                                    >

                                        {

                                            typeof item.answer ===
                                            "object"

                                                ?

                                                JSON.stringify(

                                                    item.answer,

                                                    null,

                                                    2

                                                )

                                                :

                                                item.answer

                                        }

                                    </p>

                                </div>

                            )

                        )

                        :

                        <p>

                            No Answers

                        </p>

                }

                {

                    submission.uploadedFiles?.length > 0 && (

                        <>

                            <hr />

                            <h3>

                                Uploaded Files

                            </h3>

                            <ul>

                                {

                                    submission.uploadedFiles.map(

                                        (

                                            file,

                                            index

                                        ) => (

                                            <li
                                                key={index}
                                            >

                                                <a

                                                    href={`http://localhost:5000/${file.path}`}

                                                    target="_blank"

                                                    rel="noreferrer"

                                                >

                                                    {

                                                        file.originalname

                                                    }

                                                </a>

                                            </li>

                                        )

                                    )

                                }

                            </ul>

                        </>

                    )

                }

            </div>

        </div>

    );

}

export default ViewSubmissionModal;
